1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
15	
16	// MHPCO rounds premiums up in its own favor. A float-precision guard avoids
17	// surprises like 197.5 + 0 rendering as 197.5000000001 and rounding to 198
18	// when the true mathematical value was already on an integer boundary.
19	const roundUpInMHPCOFavor = (amount: number): number =>
20	  Math.ceil(Math.round(amount * 1e6) / 1e6);
21	
22	const COMPONENT_TYPES = new Set(["rune"]);
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PREMIUM = 60;
25	
26	const itemBasePremiums = (items: Item[]): number[] => {
27	  const components: Item[] = [];
28	  const mainItems: Item[] = [];
29	  for (const item of items) {
30	    (COMPONENT_TYPES.has(item.type) ? components : mainItems).push(item);
31	  }
32	  const basePremiums = mainItems.map((item) => BASE_PREMIUM[item.type]);
33	  const countsByType = new Map<string, number>();
34	  for (const c of components) {
35	    countsByType.set(c.type, (countsByType.get(c.type) ?? 0) + 1);
36	  }
37	  for (const [, count] of countsByType) {
38	    if (count === COMPONENT_BLOCK_SIZE) {
39	      basePremiums.push(COMPONENT_BLOCK_PREMIUM);
40	    } else {
41	      basePremiums.push(count * BASE_PREMIUM.rune);
42	    }
43	  }
44	  return basePremiums;
45	};
46	
47	const quoteStep = (step: QuoteStep): { premium: number } => {
48	  const itemTotal = itemBasePremiums(step.items).reduce(
49	    (sum, base) => sum + base * (1 + FIRST_INSURANCE_SURCHARGE),
50	    0,
51	  );
52	  const total = itemTotal + PROCESSING_FEE;
53	  return { premium: roundUpInMHPCOFavor(total) };
54	};
55	
56	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
57	  const results = scenario.steps.map(quoteStep);
58	  return { results };
59	};
